// ── Confetti & finish celebration ────────────────────────────────
function launchConfetti(){
  const canvas=document.createElement('canvas');
  canvas.style.cssText='position:fixed;inset:0;width:100%;height:100%;pointer-events:none;z-index:9999';
  document.body.appendChild(canvas);
  const ctx=canvas.getContext('2d');
  canvas.width=window.innerWidth; canvas.height=window.innerHeight;
  const colors=['#7B4FD8','#4A9FD8','#f472b6','#fb923c','#a3e635','#facc15'];
  const pieces=Array.from({length:120},()=>({
    x:Math.random()*canvas.width, y:-10-Math.random()*canvas.height*0.3,
    r:4+Math.random()*5, color:colors[Math.floor(Math.random()*colors.length)],
    vx:(Math.random()-0.5)*4, vy:3+Math.random()*4,
    angle:Math.random()*360, spin:(Math.random()-0.5)*6, opacity:1
  }));
  let frame=0;
  function draw(){
    ctx.clearRect(0,0,canvas.width,canvas.height);
    pieces.forEach(p=>{
      p.x+=p.vx; p.y+=p.vy; p.angle+=p.spin;
      p.opacity=Math.max(0,1-frame/120);
      ctx.save(); ctx.globalAlpha=p.opacity;
      ctx.translate(p.x,p.y); ctx.rotate(p.angle*Math.PI/180);
      ctx.fillStyle=p.color;
      ctx.fillRect(-p.r/2,-p.r/2,p.r,p.r*1.6);
      ctx.restore();
    });
    frame++;
    if(frame<140) requestAnimationFrame(draw);
    else canvas.remove();
  }
  draw();
}

