function esc(s){ return String(s||'').replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;'); }
function diffBadge(d){ const c=d==='Easy'?'easy':d==='Medium'?'medium':'hard'; return `<span class="badge badge-${c}">${d}</span>`; }

// ── Navigation ────────────────────────────────────────────────────
let activeTab = 'projects';

function switchTab(tab){
  if(activeTab===tab) return;
  const goRight = tab==='library';
  document.getElementById('s-'+activeTab).classList.replace('on', goRight?'off-left':'off-right');
  document.getElementById('s-'+tab).classList.replace(goRight?'off-right':'off-left','on');
  document.getElementById('tab-'+activeTab).classList.remove('active');
  document.getElementById('tab-'+tab).classList.add('active');
  activeTab=tab;
  if(tab==='library') renderLibrary(); else renderProjects();
}
function goToLibrary(){ switchTab('library'); }
function goBackToProjects(){ switchTab('projects'); }

function goToDetail(type, id, from){
  currentDetailType=type; currentDetailId=id; detailFrom=from||activeTab;
  document.getElementById('back-lbl').textContent = detailFrom==='library'?'Library':'Projects';
  const eb=document.getElementById('d-edit-btn');
  if(eb) eb.style.display='block';
  if(type==='project'){
    const p=projects.find(x=>x.id===id);
    renderProjectDetail(p);
  } else {
    const p=patterns.find(x=>x.id===id);
    renderPatternDetail(p);
  }
  document.getElementById('s-detail').scrollTop=0;
  document.getElementById('s-'+detailFrom).classList.replace('on','off-left');
  document.getElementById('s-detail').classList.replace('off-right','on');
  document.getElementById('main-tab-bar').style.display='none';
}
function goBack(){
  document.getElementById('s-detail').classList.replace('on','off-right');
  document.getElementById('s-'+detailFrom).classList.replace('off-left','on');
  const eb=document.getElementById('d-edit-btn');
  if(eb) eb.style.display='none';
  currentDetailId=null; currentDetailType=null;
  document.getElementById('main-tab-bar').style.display='';
  document.getElementById('tab-projects').classList.toggle('active', detailFrom==='projects');
  document.getElementById('tab-library').classList.toggle('active', detailFrom==='library');
  activeTab=detailFrom;
}
function toggleFavDetail(){
  if(currentDetailType==='project'){
    const p=projects.find(x=>x.id===currentDetailId);if(!p)return;
    p.fav=!p.fav; saveProjects();
    const hb=document.getElementById('hero-fav-btn');
    if(hb)hb.textContent=p.fav?'★':'☆';
  } else {
    const p=patterns.find(x=>x.id===currentDetailId);if(!p)return;
    p.fav=!p.fav; savePatterns();
    const hb=document.getElementById('hero-fav-btn');
    if(hb)hb.textContent=p.fav?'★':'☆';
  }
}
function triggerDetailEdit(){
  if(currentDetailType==='project') openEditProject(currentDetailId);
  else openEditPattern(currentDetailId);
}

// ── Projects list ─────────────────────────────────────────────────
function renderProjects(){
  const q=document.getElementById('proj-search').value.toLowerCase();
  const st=document.getElementById('proj-status-filter').value;
  const list=projects.filter(p=>
    (!q||p.name.toLowerCase().includes(q)||(p.notes||'').toLowerCase().includes(q))&&
    (!st||p.status===st));
  document.getElementById('proj-count-lbl').textContent=
    `${projects.length} project${projects.length!==1?'s':''}`;
  const grid=document.getElementById('proj-grid');
  if(!list.length){grid.innerHTML='<div class="empty">No projects yet — tap + New to start one!</div>';return;}
  grid.innerHTML=list.map(p=>{
    const pat=patterns.find(x=>x.id===p.patternId);
    const steps=pat?(pat.notes||'').split('\n').filter(l=>l.trim()):
      (p.steps||[]);
    const done=getProjStepsDone(p.id);
    const pct=steps.length?Math.round(done.filter(i=>i<steps.length).length/steps.length*100):0;
    const statusCls=p.status==='Active'?'status-active':p.status==='Done'?'status-done-proj':'status-frogged';
    const photo=p.photoKey?localStorage.getItem(p.photoKey):null;
    return `<div class="card" onclick="goToDetail('project',${p.id},'projects')">
      ${photo?`<img class="card-photo" src="${photo}" alt=""/>`
              :`<div class="card-photo-placeholder"><img src="data:image/png;base64," style="width:52px;height:52px;object-fit:contain"/></div>`}
      <button class="fav-btn" onclick="event.stopPropagation();toggleFavProj(${p.id})">${p.fav?'★':'☆'}</button>
      <div class="card-body">
        <div class="card-top">
          <div class="card-title">${esc(p.name)}</div>
        </div>
        <div class="card-badges"><span class="status-pill ${statusCls}">${p.status}</span></div>
        ${pat?`<div class="proj-pattern-link">📄 ${esc(pat.name)}</div>`
             :'<div class="proj-pattern-link" style="color:var(--tx2)">✦ Freestyle</div>'}
        ${steps.length?`<div class="proj-progress-mini">
          <div class="proj-progress-mini-bg">
            <div class="proj-progress-mini-bar" style="width:${pct}%"></div>
          </div></div>`:''}
        <div class="card-meta">
          ${p.yarn?`<span>🧶 ${esc(p.yarn)}</span>`:''}
          ${p.startDate?`<span>📅 Started ${p.startDate}</span>`:''}
        </div>
      </div>
    </div>`;
  }).join('');
}
function toggleFavProj(id){
  const p=projects.find(x=>x.id===id);if(p){p.fav=!p.fav;saveProjects();renderProjects();}
}

// ── Project detail ────────────────────────────────────────────────
function renderProjectDetail(p){
  const pat=patterns.find(x=>x.id===p.patternId);
  const lines=pat?(pat.notes||'').split('\n').filter(l=>l.trim()):(p.steps||[]);
  const hasSteps=lines.length>0;
  const done=getProjStepsDone(p.id);
  const total=lines.length;
  const doneCount=done.filter(i=>i<total).length;
  const pct=total?Math.round(doneCount/total*100):0;
  const photo=p.photoKey?localStorage.getItem(p.photoKey):null;
  const isDone=p.status==='Done';


  const stepsHTML=hasSteps?`
    <div class="section">
      <div class="section-lbl">
        <span>Steps</span>
        <button class="btn-reset" onclick="resetProjSteps(${p.id})">Reset all</button>
      </div>
      ${pat?`<div style="font-size:12px;color:var(--tx2);font-weight:600;margin:-4px 0 10px;display:flex;align-items:center;gap:5px">
        <span style="opacity:.6">📄</span> Inherited from <em style="color:var(--ac);font-style:normal">${esc(pat.name)}</em>
      </div>`:''}
      <div class="progress-wrap">
        <div class="progress-meta">
          <span id="steps-lbl-${p.id}">${doneCount} of ${total} done</span>
          <span id="steps-pct-${p.id}">${pct}%</span>
        </div>
        <div class="progress-bg"><div class="progress-bar" id="steps-bar-${p.id}" style="width:${pct}%"></div></div>
      </div>
      <div class="steps-list">
        ${lines.map((line,i)=>`
          <div class="step-row${done.includes(i)?' done':''}" id="pstep-${p.id}-${i}" onclick="toggleProjStep(${p.id},${i})">
            <div class="step-check"><span class="step-tick">✓</span></div>
            <div class="step-text">${esc(line)}</div>
          </div>`).join('')}
      </div>
      ${total>0?`<div id="finish-btn-wrap-${p.id}" style="display:${doneCount===total?'block':'none'};margin-top:14px;text-align:center">
        <button onclick="finishProject(${p.id})"
          style="background:linear-gradient(135deg,#6A4FC4,#4A9FD8);color:#fff;border:none;
          padding:13px 32px;border-radius:99px;font-size:15px;font-weight:800;
          font-family:inherit;cursor:pointer;box-shadow:0 4px 16px rgba(106,79,196,.35);
          letter-spacing:.01em">🎉 Finish project</button>
      </div>`:''}
    </div>`:'';

  const photoSection=isDone?`
    <div class="section">
      <div class="section-lbl">Finished piece</div>
      ${photo
        ?`<img class="photo-preview" src="${photo}" alt="Finished piece"/>
          <button class="btn-remove-photo" onclick="removeProjectPhoto(${p.id})">Remove photo</button>`
        :`<div class="photo-upload-zone" onclick="document.getElementById('photo-fi-${p.id}').click()">
            <span style="font-size:32px">📷</span>
            <p>Tap to add a photo of your finished piece</p>
          </div>
          <input type="file" id="photo-fi-${p.id}" accept="image/*" style="display:none"
            onchange="handlePhotoSelect(event,${p.id})"/>`}
    </div>`:'';

  document.getElementById('d-content').innerHTML=`
    <div style="max-width:640px;margin:0 auto">
      <div class="detail-hero">
        <button onclick="toggleFavDetail()" id="hero-fav-btn"
          style="position:absolute;top:1rem;right:1.25rem;background:none;border:none;cursor:pointer;
          font-size:22px;color:rgba(255,255,255,.85);padding:0;line-height:1;z-index:1">${p.fav?'★':'☆'}</button>
        <div class="detail-hero-title">${esc(p.name)}</div>
        <div class="detail-hero-badges">
          <span class="status-pill">${p.status}</span>
          ${pat?`<span class="hero-info-pill hero-info-pill--link" onclick="goToDetail('pattern',${pat.id},'projects')"><img src="book.png" class="hero-pill-img"> ${esc(pat.name)} ›</span>`:''}
          ${p.yarn?`<span class="hero-info-pill"><img src="yarn-ball.png" class="hero-pill-img"> ${esc(p.yarn)}</span>`:''}
          ${p.hook?`<span class="hero-info-pill"><img src="crochet.png" class="hero-pill-img"> ${esc(p.hook)}</span>`:''}
          ${p.startDate?`<span class="hero-info-pill">📅 ${p.startDate}</span>`:''}
        </div>
      </div>
      <div class="detail-body">
        ${p.notes?`<div class="section">
          <div class="section-lbl">Notes</div>
          <div style="background:rgba(255,255,255,.7);border-radius:0 var(--rl) var(--rl) 0;padding:10px 14px 12px;
            font-size:14px;line-height:1.7;white-space:pre-wrap;border-left:3px solid var(--ac);margin:0">${esc(p.notes)}</div>
        </div>`:''}
        ${stepsHTML}
        ${photoSection}
      </div>
    </div>`;
}

function toggleInfoStrip(header){
  const chevron=header.querySelector('.info-strip-chevron');
  const body=header.nextElementSibling;
  const isOpen=body.classList.contains('open');
  chevron.classList.toggle('open',!isOpen);
  body.classList.toggle('open',!isOpen);
}

// ── Photo handling ────────────────────────────────────────────────
function handlePhotoSelect(e,projId){
  const file=e.target.files[0]; if(!file) return;
  const reader=new FileReader();
  reader.onload=ev=>{
    const key='crochet_photo_proj_'+projId;
    localStorage.setItem(key,ev.target.result);
    const p=projects.find(x=>x.id===projId);
    if(p){p.photoKey=key;saveProjects();renderProjectDetail(p);}
  };
  reader.readAsDataURL(file);
}
function removeProjectPhoto(projId){
  const p=projects.find(x=>x.id===projId);if(!p)return;
  if(p.photoKey){localStorage.removeItem(p.photoKey);p.photoKey=null;}
  saveProjects();renderProjectDetail(p);
}

