function renderLibrary(){
  const q=document.getElementById('lib-search').value.toLowerCase();
  const cat=document.getElementById('lib-cat-filter').value;
  const list=patterns.filter(p=>
    (!q||p.name.toLowerCase().includes(q)||(p.notes||'').toLowerCase().includes(q))&&
    (!cat||p.category===cat));
  document.getElementById('lib-count-lbl').textContent=
    `${patterns.length} pattern${patterns.length!==1?'s':''}`;
  const grid=document.getElementById('lib-grid');
  if(!list.length){grid.innerHTML='<div class="empty">No patterns yet.</div>';return;}
  grid.innerHTML=list.map(p=>{
    // Get first image from the pattern gallery (reuses existing storage)
    const imgs=getPatternImages(p.id);
    const previewImg=imgs.length?imgs[0]:null;
    const photoHeader=previewImg
      ?`<img class="card-photo" src="${previewImg}" alt="${esc(p.name)} preview"/>`
      :`<div class="card-photo-placeholder" style="height:100px;background:${
          ['linear-gradient(135deg,#f9c6d0,#f7a8b8)',
           'linear-gradient(135deg,#c6e8f9,#a8d4f7)',
           'linear-gradient(135deg,#c6f9d4,#a8f0c0)',
           'linear-gradient(135deg,#f9f0c6,#f7e4a8)',
           'linear-gradient(135deg,#e8c6f9,#d4a8f7)',
           'linear-gradient(135deg,#f9dcc6,#f7c4a8)',
           'linear-gradient(135deg,#c6f9f4,#a8f0e8)'][p.id % 7]}">
          <img src="${YARN_PLACEHOLDER_IMG}" style="width:56px;height:56px;object-fit:contain"/></div>`;
    return `<div class="card" onclick="goToDetail('pattern',${p.id},'library')">
      ${photoHeader}
      <button class="fav-btn" onclick="event.stopPropagation();toggleFavPat(${p.id})">${p.fav?'★':'☆'}</button>
      <div class="card-body">
        <div class="card-top">
          <div class="card-title">${esc(p.name)}</div>
        </div>
        <div class="card-badges">
          ${p.category?`<span class="cat-tag">${esc(p.category)}</span>`:''}
          ${p.difficulty?diffBadge(p.difficulty):''}
          ${p.pdfName?`<span class="pdf-badge">📄 PDF</span>`:''}
        </div>
        <div class="card-meta">
          ${p.yarn?`<span>🧶 ${esc(p.yarn)}</span>`:''}
          ${p.hook?`<span>🪝 Hook ${esc(p.hook)}</span>`:''}
        </div>
      </div>
    </div>`;
  }).join('');
}
function toggleFavPat(id){
  const p=patterns.find(x=>x.id===id);if(p){p.fav=!p.fav;savePatterns();renderLibrary();}
}

// Add / remove images from within the edit screen — refreshes the photos section in place
function addPatternImageInEdit(patId){
  const inp=document.createElement('input');
  inp.type='file'; inp.accept='image/*'; inp.multiple=true;
  inp.onchange=e=>{
    const files=Array.from(e.target.files); if(!files.length) return;
    let loaded=0;
    const imgs=getPatternImages(patId);
    files.forEach(file=>{
      const r=new FileReader();
      r.onload=ev=>{
        imgs.push(ev.target.result);
        savePatternImages(patId,imgs);
        loaded++;
        if(loaded===files.length) refreshEditPhotos(patId);
      };
      r.readAsDataURL(file);
    });
  };
  inp.click();
}
function removePatternImageInEdit(patId,idx){
  const imgs=getPatternImages(patId);
  imgs.splice(idx,1);
  savePatternImages(patId,imgs);
  refreshEditPhotos(patId);
}
function refreshEditPhotos(patId){
  // Rebuild just the photos section inside the edit screen without losing other field values
  const p=patterns.find(x=>x.id===patId); if(!p) return;
  const imgs=getPatternImages(patId);
  const thumbs=imgs.map((src,i)=>`
    <div style="position:relative;display:inline-block">
      <img src="${src}" style="width:72px;height:72px;object-fit:cover;border-radius:var(--r);display:block"/>
      <button onclick="removePatternImageInEdit(${patId},${i})"
        style="position:absolute;top:-6px;right:-6px;background:#fff;border:1.5px solid var(--bd);
        border-radius:50%;width:20px;height:20px;font-size:11px;cursor:pointer;
        display:flex;align-items:center;justify-content:center;color:var(--tx2);padding:0">✕</button>
    </div>`).join('');
  const photoGrid=`<div style="display:flex;gap:8px;flex-wrap:wrap;align-items:center">
    ${thumbs}
    <div onclick="addPatternImageInEdit(${patId})"
      style="width:72px;height:72px;border:2px dashed var(--bd2);border-radius:var(--r);
      display:flex;flex-direction:column;align-items:center;justify-content:center;
      gap:4px;cursor:pointer;background:var(--bg2);font-size:22px;color:var(--tx2)">
      📷<span style="font-size:10px;font-weight:700;color:var(--tx2)">Add</span>
    </div>
  </div>`;
  const photoSection=document.getElementById('edit-photo-section');
  if(photoSection) photoSection.innerHTML=photoGrid;
}

// ── Pattern image gallery ─────────────────────────────────────────
function getPatternImages(id){
  try{ return JSON.parse(localStorage.getItem('crochet_pat_imgs_'+id)||'[]'); }catch{ return []; }
}
function savePatternImages(id,imgs){ localStorage.setItem('crochet_pat_imgs_'+id,JSON.stringify(imgs)); }
function addPatternImage(patId){
  const inp=document.createElement('input');
  inp.type='file'; inp.accept='image/*'; inp.multiple=true;
  inp.onchange=e=>{
    const files=Array.from(e.target.files);
    let loaded=0;
    const imgs=getPatternImages(patId);
    files.forEach(file=>{
      const r=new FileReader();
      r.onload=ev=>{
        imgs.push(ev.target.result);
        savePatternImages(patId,imgs);
        loaded++;
        if(loaded===files.length){
          const p=patterns.find(x=>x.id===patId);
          if(p) renderPatternDetail(p);
        }
      };
      r.readAsDataURL(file);
    });
  };
  inp.click();
}
function removePatternImage(patId,idx){
  const imgs=getPatternImages(patId);
  imgs.splice(idx,1);
  savePatternImages(patId,imgs);
  const p=patterns.find(x=>x.id===patId);
  if(p) renderPatternDetail(p);
}
function galleryThumbClick(el){
  const pid=parseInt(el.getAttribute('data-pid'));
  const idx=parseInt(el.getAttribute('data-idx'));
  const imgs=getPatternImages(pid);
  const src=imgs[idx];
  setActiveGalleryImg(src);
}
function setActiveGalleryImg(src){
  const main=document.getElementById('gallery-main-img');
  if(main){ main.src=src; }
  document.querySelectorAll('.gallery-thumb').forEach(t=>{
    t.classList.toggle('active', t.getAttribute('data-src')===src);
  });
}

function buildPatternGallery(p){
  const imgs=getPatternImages(p.id);
  if(!imgs.length){
    return ''; // no images — hidden in read view; add photos via Edit
  }
  let thumbs='';
  for(let i=0;i<imgs.length;i++){
    const active=i===0?' active':'';
    thumbs+='<img class="gallery-thumb'+active+'" src="'+imgs[i]+'" data-idx="'+i+'" data-pid="'+p.id+'" data-src="'+imgs[i]+'" onclick="galleryThumbClick(this)" alt=""/>';
  }
  thumbs+='<div class="gallery-thumb-add" onclick="addPatternImage('+p.id+')" title="Add image">+</div>';
  return '<div class="gallery-wrap"><img id="gallery-main-img" class="gallery-main" src="'+imgs[0]+'" alt="Pattern preview"/><div class="gallery-thumbs">'+thumbs+'</div></div>';
}

